-- =========================================================
-- Invoxaco - Add New Generators (CV/Resume, Salary Slip, Company Profile)
-- Safe to run directly against an already-seeded production database.
-- Uses INSERT IGNORE so it is a no-op if these slugs already exist
-- (slug has a UNIQUE constraint on document_templates).
-- =========================================================

SET NAMES utf8mb4;

INSERT IGNORE INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (4, 'CV / Resume Generator', 'cv-resume-generator', 'Build a professional CV or resume online in minutes — add your experience and education, preview instantly, and download as PDF or DOCX.', 'Build a professional CV or resume online in minutes — add your experience and education, preview instantly, and download as PDF or DOCX.', 'bi-people', 'free', '{"fields":[{"name":"full_name","label":"Full Name","type":"text","required":true},{"name":"job_title","label":"Job Title / Desired Role","type":"text","required":true},{"name":"email","label":"Email","type":"text","required":true},{"name":"phone","label":"Phone","type":"text","required":true},{"name":"address","label":"Address","type":"textarea","required":false},{"name":"linkedin_url","label":"LinkedIn / Portfolio URL","type":"text","required":false},{"name":"professional_summary","label":"Professional Summary","type":"textarea","required":true},{"name":"work_experience","label":"Work Experience","type":"group_list","required":true,"columns":[{"name":"position","label":"Job Title","type":"text"},{"name":"company_dates","label":"Company & Dates","type":"text"},{"name":"details","label":"Responsibilities & Achievements","type":"textarea"}]},{"name":"education","label":"Education","type":"group_list","required":true,"columns":[{"name":"degree","label":"Degree","type":"text"},{"name":"institution_dates","label":"Institution & Dates","type":"text"},{"name":"details","label":"Details","type":"textarea"}]},{"name":"skills","label":"Skills","type":"textarea","required":false},{"name":"certifications","label":"Certifications","type":"textarea","required":false},{"name":"languages","label":"Languages","type":"textarea","required":false}]}', '[{"q":"Is the CV / Resume Generator free to use?","a":"Yes, every Invoxaco plan includes access to the CV and resume builder. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download my CV as PDF and Word?","a":"Yes. Every CV you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file you can keep editing."},{"q":"Can I add multiple jobs and education entries?","a":"Yes, the Work Experience and Education sections let you add as many entries as you need, each with its own title, dates, and details."}]', 1, 1, 'CV / Resume Generator - Free Online CV / Resume Generator | Invoxaco', 'Create a professional CV or resume online free with Invoxaco. Fill a simple form, preview instantly, and download as PDF or Word.', 12);
INSERT IGNORE INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (4, 'Salary Slip Generator', 'salary-slip-generator', 'Create a professional salary slip / payslip online in minutes — add earnings and deductions, preview instantly, and download as PDF or DOCX.', 'Create a professional salary slip / payslip online in minutes — add earnings and deductions, preview instantly, and download as PDF or DOCX.', 'bi-people', 'free', '{"fields":[{"name":"payslip_number","label":"Payslip Number","type":"text","required":false},{"name":"pay_period","label":"Pay Period","type":"text","required":true},{"name":"pay_date","label":"Pay Date","type":"date","required":true},{"name":"from_name","label":"Employer","type":"textarea","required":true},{"name":"to_name","label":"Employee","type":"textarea","required":true},{"name":"earnings","label":"Earnings","type":"line_items","required":true},{"name":"deductions","label":"Deductions","type":"line_items","required":true},{"name":"net_pay","label":"Net Pay","type":"number","required":true},{"name":"payment_mode","label":"Payment Mode","type":"text","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false}]}', '[{"q":"Is the Salary Slip Generator free to use?","a":"Yes, every Invoxaco plan includes access to the salary slip tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the salary slip as PDF and Word?","a":"Yes. Every payslip you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Does it calculate the net pay automatically?","a":"You enter the earnings and deductions line items and the net pay amount, so you stay in control of rounding and statutory deductions specific to your country."}]', 1, 1, 'Salary Slip Generator - Free Online Salary Slip Generator | Invoxaco', 'Create a salary slip or payslip online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word.', 13);
INSERT IGNORE INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (9, 'Company Profile Generator', 'company-profile-generator', 'Create a professional company profile online in minutes — showcase your mission, products, and achievements, then download as PDF or DOCX.', 'Create a professional company profile online in minutes — showcase your mission, products, and achievements, then download as PDF or DOCX.', 'bi-megaphone', 'free', '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"tagline","label":"Tagline","type":"text","required":false},{"name":"founded_year","label":"Founded Year","type":"text","required":false},{"name":"industry","label":"Industry","type":"text","required":false},{"name":"company_overview","label":"Company Overview","type":"textarea","required":true},{"name":"mission_statement","label":"Mission Statement","type":"textarea","required":false},{"name":"vision_statement","label":"Vision Statement","type":"textarea","required":false},{"name":"core_values","label":"Core Values","type":"textarea","required":false},{"name":"products_services","label":"Products & Services","type":"group_list","required":false,"columns":[{"name":"name","label":"Name","type":"text"},{"name":"category","label":"Category","type":"text"},{"name":"description","label":"Description","type":"textarea"}]},{"name":"why_choose_us","label":"Why Choose Us","type":"textarea","required":false},{"name":"clients_achievements","label":"Clients & Achievements","type":"textarea","required":false},{"name":"contact_details","label":"Contact Details","type":"textarea","required":false},{"name":"website","label":"Website","type":"text","required":false},{"name":"social_media","label":"Social Media","type":"text","required":false}]}', '[{"q":"Is the Company Profile Generator free to use?","a":"Yes, every Invoxaco plan includes access to the company profile tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the company profile as PDF and Word?","a":"Yes. Every company profile you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I list multiple products or services?","a":"Yes, the Products & Services section lets you add as many entries as you need, each with its own name, category, and description."}]', 1, 1, 'Company Profile Generator - Free Online Company Profile Generator | Invoxaco', 'Create a professional company profile online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word.', 12);
